"""
adapters/prismlang.py — PrismLang Integration Adapter

Bridges PrismLang's encoder + TaxonomyConfig into PrismResonance's
amplitude + FrequencyFamily ingestion pipeline.

PrismLang is installed from: C:/code/PrismLang
  pip install -e C:/code/PrismLang

This adapter:
  1. Uses PrismLang's ONNX encoder (all-MiniLM-L6-v2, 384-d) to produce
     the amplitude vector (A) for each text chunk.
  2. Maps PrismLang TaxonomyConfig category slugs to FrequencyFamily
     phase angles via a user-supplied slug→FrequencyFamily mapping.
  3. Returns (amplitude, phase) ready for surf_and_flag().
"""

from __future__ import annotations

from typing import Dict, List, Optional, Tuple

import numpy as np

from ..frequency import FrequencyFamily


class PrismLangAdapter:
    """
    Encode text chunks using PrismLang and map taxonomy categories to
    FrequencyFamily phase angles.

    Parameters
    ----------
    slug_to_family : dict mapping PrismLang category slug → FrequencyFamily.
                     Unmatched slugs default to FrequencyFamily.NEUTRAL.

    Example
    -------
    ::

        from prismresonance.adapters.prismlang import PrismLangAdapter
        from prismresonance.frequency import FrequencyFamily

        adapter = PrismLangAdapter(slug_to_family={
            "error":    FrequencyFamily.EMERGENCY,
            "recovery": FrequencyFamily.RECOVERY,
            "config":   FrequencyFamily.NORMAL,
        })

        amplitude, phase = adapter.encode_chunk("Database connection timeout")
    """

    def __init__(
        self,
        slug_to_family: Optional[Dict[str, FrequencyFamily]] = None,
    ) -> None:
        self._slug_map = slug_to_family or {}
        self._encoder  = None   # lazy load

    def _get_encoder(self):
        if self._encoder is None:
            try:
                from prismlang import encoder as _enc
                self._encoder = _enc
            except ImportError as exc:
                raise ImportError(
                    "PrismLang is required: pip install -e C:/code/PrismLang"
                ) from exc
        return self._encoder

    def _infer_family(self, text: str) -> FrequencyFamily:
        """Heuristic phase assignment from text keywords when no taxonomy given."""
        lower = text.lower()
        if any(w in lower for w in ("error", "fail", "timeout", "crash", "exception")):
            return FrequencyFamily.EMERGENCY
        if any(w in lower for w in ("recovery", "retry", "restore", "fix")):
            return FrequencyFamily.RECOVERY
        if any(w in lower for w in ("alert", "warn", "anomaly", "spike")):
            return FrequencyFamily.ALERT
        if any(w in lower for w in ("archive", "historical", "old", "deprecated")):
            return FrequencyFamily.ARCHIVE
        return FrequencyFamily.NORMAL

    def encode_chunk(
        self,
        text: str,
        category_slug: Optional[str] = None,
    ) -> Tuple[np.ndarray, float]:
        """
        Encode a single text chunk.

        Returns
        -------
        (amplitude, phase_angle)
            amplitude   : (384,) float32 unit vector from PrismLang encoder
            phase_angle : float — FrequencyFamily value
        """
        encoder = self._get_encoder()
        amplitude = encoder.encode(text)   # (384,) float32

        if category_slug and category_slug in self._slug_map:
            family = self._slug_map[category_slug]
        else:
            family = self._infer_family(text)

        return amplitude, float(family)

    def encode_batch(
        self,
        texts: List[str],
        category_slugs: Optional[List[Optional[str]]] = None,
    ) -> Tuple[np.ndarray, List[float]]:
        """
        Encode a batch of text chunks.

        Returns
        -------
        (amplitudes, phases)
            amplitudes : (M, 384) float32
            phases     : list of M float phase angles
        """
        encoder    = self._get_encoder()
        amplitudes = encoder.encode_batch(texts)   # (M, 384) float32
        slugs      = category_slugs or [None] * len(texts)

        phases = []
        for text, slug in zip(texts, slugs):
            if slug and slug in self._slug_map:
                phases.append(float(self._slug_map[slug]))
            else:
                phases.append(float(self._infer_family(text)))

        return amplitudes, phases
